def fib(n):
    # Calculate Fibonacci number for mathematical modeling
    # Input guard
    if n < 0:
        raise ValueError('Negative N')

    # PROBLEM: Naive recursion recomputes values exponentially
    # fib(30) will take seconds. fib(40) minutes.
    # Should use @functools.lru_cache or iterative approach
    if n <= 1:
        return n

    # Recursive calls without memoization
    return fib(n-1) + fib(n-2)

